from sklearn.preprocessing import MinMaxScaler
import numpy as np

def task_func(myList):
    if not isinstance(myList, (list, np.ndarray)):
        raise TypeError("Input must be a list or NumPy array.")

    scaler = MinMaxScaler()
    data = np.array(myList)
    normalized_data = scaler.fit_transform(data[:, None])

    return tuple(normalized_data.flatten())
